insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='RODRIGUEZ'and apellido2='CALERO'),'2011-01-20','MANTENEMOS ENTREVISTA CON CARMEN DIAZ , T.S. DEL ESM DE VALDEPALILLAS Y HACEMOS VISITA A DOMICILIO. PLAN DE INTERVENCION INDIVIDUAL : *PARTE SOCIAL : PASAR EL CASO A FUTUEX PARA INICIAR ACOMPAÑAMIENTO .TIENE EL SEGUIMIENTO DEL ESM , DE TELEASISTENCIA DE CRUZ ROJA , SAD .. BUENA RELACIÓN VECINAL. POR EL MOMENTO PUEDE PERMANECER EN SU DOMICILIO . EL DEMANDA IR A UNA R.MAYORES DE GUADALAJARA PARA ACERCAMIENTO FAMILIAR , LA PLAZA ES DE 1500€ Y SUS INGRESOS DE 1043 CON LO QUE NO ES FACTIBLE. SE LE VA A TRAMITAR LAAD PARA VER SI SE PUEDE SOLICITAR RECURSO VIA PIA. *PARTE ECONOMICA. -DOMICILIAR TODOS LOS GASTOS FIJOS. -REINTEGROS QUINCENALES PARA GASTOS DE BOLSILLO Y COMIDA. -PTE. PAGO COLLECTA DE 6 CUOTAS .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CORAL'and edp.apellido1='NEVADO'and apellido2='NAVARRO'),'2011-01-25','SE SOLICITA INFORMACIÓN A CAJA DE EXTREMADURA EN CACERES SOBRE SU CUENTA HAY QUE SOLICITAR PRESTACIÓN DE ORFANDAD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2011-01-28','ACOMPAÑAMIENTO A CADEX BJOZ. PARA REVISION DEL GRADO DE DISCAPACIDAD Y PERFIL. DESDE EL CTRO.PENITENCIARIO LE HAN CONCEDIDO LA LIBERTAD CONDICIONAL HASTA AGOSTO 2011 QUE CUMPLE LA PENA TOTAL DE 4 AÑOS QUE TENÍA IMPUESTA. SIN EMBARGO DESDE EL CADEX NO LO VEN APTO PARA PERFIL . VICHO COMENTA QUE HA TENIDO PELEAS EN EL CENTRO EN VARIAS OCASIONES, HA SIDO TRASLADADO DE MÓDULO EN 3 VECES , NO QUIERE CONTINUAR CON EL TRATAMIENTO MÉDICO QUE TIENE PRESCRITO Y MANTIENE CONSUMO ACTIVO DE DROGAS. TODO ELLO HACE QUE NO SEA POSIBLE SU TRASLADO A CENTRO DE DISCAPACIDAD. QUEDO PTE. DEL INFORME DEL CTRO. PENITENCIARIO COMUNICANDO LA LIBERTAD CONDICIONAL PARA PODER REBOCARLA CON EL INFORME PERTINENTE DEL CADEX . SI EL GRADO DE DICAPACIDAD AUMENTA AL 65% SE LE GESTIONARÍA PNC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2011-02-01','SE ENVIA AL CTRO. PTRO. BADAJOZ EL INFORME ABREVIADO DEL CADEX POR EL QUE SE AUMENTA SU GRADO DE DISCAPACIDAD AL 68% Y NO ES APTO PARA NINGUN PERFIL .SE ENVIA A LA T.S. DEL MODULO 3 QUE LO PASARÁ A JUNTA , DONDE DECIDIRÁN SI SALE EN LIBERTAD CONDICIONAL.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='ALCANTARA'),'2011-02-04','Isabel está en aprosuba6 . Tiene plaza residencial y acudía al CO . Se ha solicitado acceso a Centro de Dia , nos piden Informe médico que enviarán desde el centro .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IGNACIO'and edp.apellido1='RODRIGUEZ'and apellido2='ALCANTARA'),'2011-02-04','Según Julian (Aprosuba 6 ) el chico ingresó sin cumplir el protocolo MADEX pq la familia le introdujo en el coche de la asociación cuando fueron a recoger a su hna.Este aspecto es dudoso , se dieron numerosas irregularidades y no quisieron esperar la asignación de plaza. El contrato de plaza residencial está pte. de firmar , se le entregó a Manuela Delgado para su estudio y valoración. Ignacio, según el , ingresó con eccemas en la piel y mal aspecto físco . Ha estado 2 semanas ingresado en la unidad hospitalaria de Salud Mental. Se encuentra adaptado.','2');
