insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='AVILES'and apellido2='ZANCADA'),'2011-07-22','- ESTA SEÑORA ES DEFENSA JUDICIAL . EL JUZGADO NOS HA DADO TB EL CARGO DE TUTOR PERO ESTÁ RECURRIDO POR ESCALONA EN BENEFICIO DE UN FAMILIAR . LA SEÑORA ES MAYOR , PRESENTA ALCOHOLISMO CRONICO Y E.MENTAL LA T.S. DEL SSB DE SANTA ANA ME MANDA INFORMES PARA SOLICITUD DE PLAZA EN R. MAYORES . SIN EMBARGO SERIA NECESARIO TRTAR DE COMPENSAR SU ADICCION EN C. TERAPEUTICA CON LO QUE SE SOLICITA CITA CON LA S.G. DROGAS . ES DIFICIL Q ENTRE EN LA RED DE S.MENTAL CONSUMIENDO . SI VEMOS QUE TARDA ESTA CITA CON S.T. DROGAS , PROCEDEMOS AL INTERNAMIENTO EN R. MAYORES , YA TENEMOS LA AUTORIZACION JUDICIAL PARA ELLO .','2');
