insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2011-06-30','-HE CONTACTADO NUEVAMENTE CON LA T.S DESL SSB . TIENE 63 AÑOS Y ENF. MENTAL . PARA R. MAYORES SERIA PRIVADA , TIENE UNA PENSION DE 1700€ Y EN TODO CASO INVOLUNTARIO . PARA LA RED DE SALUD MENTAL , NO TENEMOS INFORMACION DE SU ESTADO ACUTAL . VOY A ESPERAR A QUE SEA VALORADO POR DEPENDENCIA PARA OBTENER MÁS DATOS. NO HAY AGRESIONES CON FAMILIARAES NI VECINOS . APARENTEMENTE TRANQUILO.','2');
