insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MANUEL'and edp.apellido1='BLAZQUEZ'and apellido2='SANDOVAL'),'2011-07-12','-Resuelto por Emergencia Social plaza de RAL en Novaforma desde el 1 de julio de 2011.Este servicio incluye C. O.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FERNANDEZ'and apellido2='MERCHAN'),'2011-07-12','En CRR desde noviembre de 2011. Últimamente parece tener "lagunas" que están observando en algunos momentos y determinados comentarios de D.Antonio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CORAL'and edp.apellido1='NEVADO'and apellido2='NAVARRO'),'2011-07-13','- se solicita PF . Optaremos por esta y dejaremos la PNC que se solicitó en principio pero al darle el CAMP y coincidir con su hno. no nos interesa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='LOPEZ'and apellido2='CORBACHO'),'2011-07-05','Asistencia a la Sucomisión de Gestión de Casos de Plasencia. (05-julio-2011) · Asistentes: Representantes del E.S.M., U.R.H. y E.A.P.II de Plasencia, de la Sudirección de Salud Mental y de CTAEx. · Conclusiones: 1. Se determinó que el CRR de Plasencia no es el lugar adecuado para el tratamiento del caso de D. Feliciano, tanto por considerar que no se encuentra capacitado para desenvolverse en un medio abierto, como por la actitud y comportamiento que ha ido pasando progresivamente a un aislamiento cada vez mayor, con expresión de su deseo de marcharse a un piso el solo y, recurriendo para la consecución de su deseo a la mentira (simular delito) y a la amenaza de muerte (focalizada en este momento en la Psiquiátra del E.S.M.). 2. Los presentes parecían estar de acuerdo en que este caso es difícilmente recuperable para cualquier medio abierto y ello no solo por los antecedentes del mismo, sino por lo que en las entrevistas con la Psiquiátra se ha podido corroborar: +no conciencia de enfermedad; +convencimiento por su parte de que los hechos que protagonizó hace 27 años fueron un acto de justicia. +se considera en todo momento una persona justa, haciendo justicia cuando no se cumplen sus deseos. +frialdad afectiva.Las amenzas y subterfugios con las que trata de conseguir su deseo de irse a un piso o, si no es esto posible, volver al C. Sociosanitario de Plasencia y, en su caso, al Psiquiátrico Penitenciario de Alicante, no son fruto de un momento de crisis, sino que demuestran una elaboración meditada para la consecución de estos objetivos, aumentando esto el riesgo de su posible cumplimiento. +en ningún momento se ha podido establecer con su Psiquiatra una relación terapéutica. · Decisión: remitir de nuevo al paciente al C. Sociosanitario de Mérida por: 1. No ser el CRR de Plasencia un medio adecuado para él; 2. Por considerar que la medida de alejamiento de su localidad no parece ser necesaria por cuanto durante el tiempo que ha estado aquí ha tenido la posibilidad de coger un autobús y marcharse allí, por lo que se puede "presumir" que no es un deseo que él tenga; 3. Porque es un paciente de dicha Área de Salud y, dado los presupuestos anteriores, no parece procedente mantenerlo en una Área distinta de la suya. · Como representante de CTAEX expuse los siguientes aspectos a considerar: · 1. Incidir en lo que motivó el tralado de D. Feliciano a Plasencia, el alejamiento de su localidad, no solo por lo que él pudiera hacerle a terceros (recordando que las dos personas que inicialmente fueron su "objetivo" no fueron luego sus víctimas) sino lo que terceros le pudieran hacer a él. 2. El hecho de que no haya hecho mención explícita de sus deseo de "volver", unido al hecho de que se considere si tiene o no capacidad para utilizar los medios necesarios para ello (bus), no garantiza en absoluto que no pueda ocurrir ese retorno. 3. Caso de llevarse a cabo definitivamente el traslado, procurar hacerlo dentro de la mayor naturalidad posible, sin que el paciente pueda establecer un vínculo entre sus comportamiento actual y la decisión tomada, lo cuál supondría para él un refuerzo positivo. 4. Y por último, las respuesta más que previsible del C. Sociosanitario de Mérida según el informe remitido a esta Comisión Tutelar, que leí a los presentes con la finalidad de recordárselo, dándome cuenta de que lo desconocían, lo cual motivo el "desconcierto" entre ellos por considerar los datos que en él aparecen de suma relevancia.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='LOPEZ'and apellido2='CORBACHO'),'2011-07-13','Reunión con el Dr. José Gómez Romero, Psiquiátra de la UHB de Mérida. Elaboraremos un informe de la situación actual de Feliciano que remitiremos,él a la Fiscalía y yo al Juzgado de 1ª Instancia nº 4 de Mérida.','2');
