insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='AVILES'and apellido2='ZANCADA'),'2011-07-11','Asistencia al Hospital Nuestra Señora de la Montaña para estar presente en la valoración del Cadex. Dª Rosa Firma el Ingreso en Centro Residencial una vez explicado en qué consite, quedando en acompañarla si me es posible el día del traslado.','2');
