insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='VAZQUEZ'and apellido2='CORRALES'),'2011-07-20','Solicitud de Expediente de Juisdicción Voluntaria al Juzgado d 1ª Instancia e Instr. nº1 de Zafra. Se trata de hablar con su médico de familia, el Dr. Eduardo Berciano, pereo está de vacaciones. Queda pendiente llamarlo en agosto.Su sustituta ,Dra. Diana Jaime, desconoce el caso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='AVILES'and apellido2='ZANCADA'),'2011-07-22','Alta hospitalaria en la UHB del Hospital Nuestra Señora de la Montaña. Ingreso este mismo día en EL C.R. "La Granadilla". Tiene cita en Neumología en el H. San pedro de Alcántara el 28 de julio. Graci, la médico de la Residencia le va a tramitar otra cita en badajoz para evitar el desplazamiento.','2');
