insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='MORENO'and apellido2='BORREGUERO'),'2011-08-11','- el informe social que tenemos en el expediente es del 2009, he hablado con Lola Bernal ( T.S. de Siruela ) y me dice que la situación es la misma . Hay que solicitar autorizacion para internamiento involuntario en Centro de Mayores. -Pte . hacer el inventario. No se pueden controlar las cuentas bancarias pq la pensión la cobra por ventanilla . El dinero lo tienen en casa .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2011-08-18','-Jesú ha ingresado en el Centro Penitenciario de Soto del Real , tras su ultima fuga del centro de las Cumbres en Avila . -Hemos solicitado revocacion de esta condena , el juzgado nos remite que de debe ser el Equipo Multidisciplinar pentenciario el que haga esta propuesta. Se remite fax con todo ello al centro . - Su cuenta peculio , tras hablar con Monica ( TS ) se establece en treinta euros mensuales , revocando las ordenes anteriores.','2');
