insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='VAZQUEZ'and apellido2='CORRALES'),'2011-08-19','-A las 14.30 recibo llamada de PIlar , T.S. del SSB de Los Santos de Maimona . La situación es de urgencia , este señor está sentado en la calle a 40º de calor , no come , y está en una situación de desamparo total . En vista de que no tenemos respuesta a nuesta solicitud de autorización para internamiento en CSS pedida al juzgado el 19 de Julio , insto a mi colega para que le comente el caso al médico de cabecera para que active el 112. Le envio la documentación que desde aquí enviamos al juzgado.','2');
