insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2011-09-05','Carolina, del CRR de Plasencia. Guadalupe a sufrido un intento autolítico esta madrugada, intentando cortarse las venas con una cuchilla que al parecer compró ayer al salir del Centro. La compañera de habitación se dió cuenta sobre las 06.00 de la mañana, dándose parte al 112 y trasladándola al H. "Virgen del Puerto" donde permanece ingresada en observación. Según el Psiquiátra, hubo realmente intención de suicidio, manifestando la paciente sus deseos de morir. Dicho deseo ha surgido hace unos días, según refiere Carolina, porque nunca antes se habían manifestado intencónes de esta índole. Han registrado la habitación encontrando tres cuchillas, pero volverán a hacerlo porque los paquetes suelen ser de cinco. Nos enviará en informe del 112 tras el ingreso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARCELO'and edp.apellido1='MANZANO'and apellido2='PEREZ'),'2011-09-06','Se encuentra en la Residencia de Mayores de Hoyos. La plaza que ocupa cuesta 790 € que abona la hermana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL CARMEN'and edp.apellido1='RAMOS'and apellido2='SANCHEZ'),'2011-09-06','Ingresó en el Hospital "Virgen de la Montaña" el día 26 de agosto por una rectorragia. Le dieron el alta ayer, día 05 de septiembre: según Lourdes, Enfermera del Centro de Mayores, se encuentra bien. Nos envía Informe de Alta. Desde el Centro estuvieron en contacto con la familia y les informaron de la situación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTOS'and edp.apellido1='ALVES'and apellido2='MOYA'),'2011-09-05','Programado traslado de D. Santos al CSS de Plasencia para el 12 de septiembre. Lo regogerá un Taxi (Radiotaxi Badajoz) a las 08:30h en el CRR de Badajoz. Lo acompañará una Delegada de Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2011-09-06','Ingresó en la UHB del H. "Nuestra Señora del Puerto" tras pedir en el CRR que deseaba acudir al Hospital por que no se encontraba bien. Manifestaba tener dolores de cabeza e intenciones de autolesionarse.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='VAZQUEZ'and apellido2='CORRALES'),'2011-09-05','Se comunica al Juzgado de Primera Innstancia e Instrucción nº 2 de Zafra el ingreso Hospitalario, posterior Alta e ingreso en el centro de Mayores de Casar de Palomero de D. Juan Vázquez Corrales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CORAL'and edp.apellido1='NEVADO'and apellido2='NAVARRO'),'2011-09-06','-coral ya ha sido valorada por la Dependencia , pte. del certificado de grado y nivel para enviar a la seguridad social en referencia al complemento de ATP para la prestación de PF.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICENTA'and edp.apellido1='SUTILLO'and apellido2='HERMOSO'),'2011-09-07','Se envía aceptación del cargo de Defensor Judicial a Gabinete Jurídico por fax y correo ordinario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2011-09-09','Informe de javier, director CRR de Plasencia. Ayer, día 8 de septiembre, José María se escapó del centro sobre las 19 h y se fue en autobús hasta Coria, sin dinero para la vuelta ni medicación. Se puso la denuncia y fue trasladado de Coria a Plasencia por la G. Civil. y un médico. Desde el CRR la G. Civil lo tuvo que "reducir" nuevamente para llevarlo al H. "Virgen del Puerto" donde el Psiquiatra determino que podía volver al CRR(eran las 04 h de la madrugada. Javier teme que hoy, viernes, intente volver a escaparse. Quedo en llamarlo sobre las 13h para hablar sobre todo ello y preguntar a los compañeros por la consulta que tiene hoy con el Psiquiatra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='CAYERO'and apellido2='AGUILAR'),'2011-10-12','-aprobada la PF con el cpto. de tercera persona. -Pensión actual : PF ( 521,40) + P. Orfandad ( 183,70)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA DE LOS REMEDIOS'and edp.apellido1='PALOMO'and apellido2='GONZALEZ'),'2011-10-12','- Acompaño a Juana a revisión del CADEX , quedamos a la espera del nuevo Cdo. y ver si llega al 65% para solicitar PNC. -En los ultimos meses y segun entrevista con la TS y la psicologa del centro " La Luz" la chica ha mejorado su conducta . Esto ha sido posible por el inicio de tratamiento de enfermedad mental que la tiene mucho más relajada. Si su evolución es buena puede permanecer en el centro sin necesidad de traslado .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LAZARO'and edp.apellido1='LUBIAN'and apellido2='SANTANO'),'2011-09-12','Hablo con Mª Paz (Sudirección de Salud Mental). Tras la gestión de Miguel Simón con Javier Berrocoso, este último quedó con Miguel Medina, Psiquiatra de Lázaro, en que éste realizaría directamente la derivación a UHB. Quedamos en que Mª Paz hablará con el Psiquiatra y me llamará. Mari Paz ha intentado hablar con Miguel Medina paro está de vacaciones hasta el 19 de sept. El próximo lunes hablará con él y me llamará.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2011-09-12','H. Infanta Cristina. Neurología: Dr. Justo Vialas Simón (6ª lanta, Esxt. 48653). Se le solicita informe sobre la enfermedad de Luis alberto, a petición de Aprosuba 8, ante las dudas que les surgen a los cuidadores en relación a la mejor atención que pueden dispensarle en torno a la misma (ejercicio físico, perodicidad de las revisiones oftálmicas, etc). El Dr. Vialas considera que dichas dudas no se pueden resolver de forma general, sino personalizadamente cuando nuevamente acuda a consulta con sus cuidadores, respondiendiendo entonces de forma concreta a las situaciones que viven con él día a día. Al habla con Pepa, Directora de Apba. 8, le informo de lo hablado con el médico y quedamos en que me avisarán de la próxima consulta que tenga programada Luis Alberto, a la cual podemos acudir como Tutores además de la Coordinadora de Apba. 8.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA FERNANDA'and edp.apellido1='ALVAREZ'and apellido2='RODRIGUEZ'),'2011-09-13','-HA FALLECIDO ESTA MADRUGADA . SE LE VA A HACER LA AUTOPSIA . NO TIENE SEGURO DE DECESOS . TIENE DINERO EN CUENTA PARA PAGAR EL SEPELIO. INTENTAMOS CONTACTAR CON SU HNO. MANUEL PARA COMUNICÁRSELO. ESTA CHICA ESTABA PTE. DE UN CAMBIO DE RECURSO POR SUS GRAVES PROBLEMAS CONDUCTUALES.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA NIEVES'and edp.apellido1='HERREROS'and apellido2='ORIVE'),'2011-09-13','Se envía Informe a Gabinete Jurídico (Curro) en respuesta a la demanda de D. Ramón, marido de Dª Mª Nieves, de remover el cargo de Tutor de la CTAEx. Se habla con Verónica, T. Social de "Felipe Trigo", sobre dicha demanda. Respecto de la dentadura de Dª Mª Nieves, hoy le han quitado la última pieza dental, en espera de que cicatrice para hacerle la dentadura definitiva.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='MARTIN'and apellido2='MARTIN'),'2011-09-13','-SE ENVIAN INFORMES MEDICOS AL EVI DEL INSS DE CACERES PARA SU VALORACION Y EN SU CASO RECONOCIMIENTO AL DERECHO DE P. DE ORFANDAD.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='MORENO'and apellido2='BORREGUERO'),'2011-09-13','-SE ENVIA EXPE. JURISDICCION VOLUNTARIA PARA INTERNAMIENTO INVOLUNTARIO EN R. MAYORES.','2');
