insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2011-09-15','-PERCIBE PNC. SE SOLICITA PF + P.ORFANDAD. SI SE LA APRUEBAN RENUNCIAREMOS A LA PNC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='BLAZQUEZ'and apellido2='ACEDO'),'2011-09-16','-es una curatela para la supervisión del tratamiento psiquiatrico y control del alcoholismo. Está en la R.M. Hernando de Soto de Jerez de los Caballeros. Deberíamos valorar la posibilidad de un mayor control del alcoholismo : CEDEX , Asociación de alcohólicos...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2011-07-10','-tiene solicitada Ley de Dependencia y ya ha sido valorado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2011-09-10','-solicitada y valorada por Ley de dependencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2011-09-10','-solicitada y valorada Ley de Dependencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2011-09-16','-percibe PNC. Se le gestiona PF+ Orfandad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL GONZALO'and edp.apellido1='MORENO'and apellido2='GOMEZ'),'2011-09-16','Citación parea declarar en Juzgado de Instrucción nº 4 de Don Benito. Finalmente esta declaración se desveló innecesaria por cuanto quien debía declarar era otra persona (Manuel) que había realizado una denuncia falsa. A Ángel se le ha realizado hace unos días en Urgencias una gastroscopia por los problemas que presentaba en la garganta y que le impiden tragar y hablar con normalidad, al parecer debido al exceso de medicación, especialmente de Aloperidol (1/2-0-1/2) que ya se le ha reducido en dos ocasiones. Se le ha pedido una ecografía para Otorrino que se hará a finales de septiembre. También se le ha pedido desde Apba 9 un adelanto de la consulta en Salud Mental que no se ha considerado oportuna por parte del especialista.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='LOPEZ'and apellido2='CORBACHO'),'2011-09-16','Conversación telefónica mantenida con el Dr. José Gómez, de la UHB de Mérida. Al igual que en la CTAEx, considera que la situación de D. Feliciano está en un "callejón sin salida". Ante la insitencia de éste de irse a vivir a un CRR, piso tutelado o incluso a un piso de alquiler no cabe otra cosa que ir tratando de contener dicho deseo en el tiempo, con el riesgo creciente de que finalmente el se de cuenta de la realidad y opte por conductas ya llevadas a delante con anterioridad: amenazas de muerte a diferentes profesionales, no espontáneas sino meditadas con meticulosidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LAZARO'and edp.apellido1='LUBIAN'and apellido2='SANTANO'),'2011-09-19','Conversación con Mari Paz (Subdircc. de Salud Mental). Sobre derivación a UME de Lázaro me indica que hable directamente con Miguel Medina, su Psiqiatra del ESM de Trujillo (927-320769). Al habla con Miguel me dice que descaonoce qué ha podido pasar con esa derivación porque se acaba de incorporar de las vacaciones. El la dejó hecha a mediados de agosto. Llamo a la UME de Plasencia para comprobar que esta derivación les haya llegado: hablo con Mariví y va a hablar con Pilar para averiguar qué ha pasado. Me llamará. Llamo a Nati, del Servicio de Gestión de Penas (927-278647), para que sepa que estoy buscando la mencionada información.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GREGORIO'and edp.apellido1='LOPEZ'and apellido2='CABRERA'),'2011-09-19','Hablo con el Centro de Reconocimiento de Conductores (C/. Luis Álvarez Lencero, de Badajoz. Cristina, Médico, 924-223217). No hay incoveniente alguno de que gregorio se pueda sacar el carnet de ciclomotor si pasa el reconocimiento psicofísico y no está incurso en níngún delito. Sí sería conveniente que contase con documentación relativa a sus discapacidad (Certificado Cadex). Por otra parte, Soledad ("La LUz") me comenta que respecto a la casa de la que posee la mitad de la propiedad junto con su hermana y hermano, ya está hecha la declaración de herederos. Su tía, que posee la otra mitad, lo ha puesto en manos de una abogada, Ángela, para todos estos trámites.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOBAL'and edp.apellido1='CASQUERO'and apellido2='GARCIA'),'2011-09-19','-percibe pnc , compatible con el contrato de trabajo que ha empezado . La pnc asciende a 190€/ mes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LAZARO'and edp.apellido1='LUBIAN'and apellido2='SANTANO'),'2011-09-21','Conversación telefónica con Pilar Bueno (T.Soc. UME CSS Plasencia). La derivación a UME se realizó, pero de manera muy poco específica. En el Equipo se valoró que este caso NO PRESENTA PERFIL PARA UME ya que el único problema existente es el alcoholismo que presenta D. Lázaro. Pilar no me puede decir si se comunicó dicho rechazo del caso al dr. Miguel Medina, Psiquiatra del ESM de Trujillo. Lo comprobará cuando Rosa, la Admva. de la Unidad vuelva de vacaciones. Le pido que , además de enviárselo a Miguel Medina, nos envíe una copia de dicho Informe a la Comisión. La propuesta es llevarlo a CEDEX y desde allí derivarlo a la Unidad de Alcoholismo. Informo a Pilar de la imposibilidad de ello ante la negativa de D. Lázaro para acudir a este recurso de forma voluntaria. Comunico a Nati, del S. de Gestión de Penas estos últimos datos. Alternativas que plantear desde CTAEx: 1.-Convencer a D. Lázaro de que el paso previo para pasar a otro Centro es el CEDEX. 2.-Hablar con Miguel Medina para valorar como viable el ponerlo en lista de espera de CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MANUEL'and edp.apellido1='BLAZQUEZ'and apellido2='SANDOVAL'),'2011-09-21','SE LE ASIGNAN 100 € MENSUALES PARA GASTOS PERSONALES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GREGORIO'and edp.apellido1='LOPEZ'and apellido2='CABRERA'),'2011-09-21','PENDIENTES DE RECIBIR EXTRACTOS DE CUENTAS DE CAJA BADAJOZ Y LA CAIXA, VER LO QUE SACA LA DIRECTORA MENSUALMENTE Y AUTORIZARLE 100 € MENSUALES PARA QUE EL SE LO ADMINISTRE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FERNANDO'and edp.apellido1='BRONCANO'and apellido2='MARTIN'),'2011-09-22','Se recibe llamada en la CTAEx de D. Manuel Martín, sobrino de D. Fernando. Tlf. 686-777025. Ha venido de Barcelona, asesorado por su abogado, para entrar en la casa de su tío. Se le informa de que se ha realizado la Rendición Final de Cuentas y que se está pendiente de su aprobación por parte del Juzgado. En tanto no tengamos esa aprobación, y haya declaración de herederos y aceptación de la herencia no puede acceder a la vivienda. Hablamos con la T.Social del Ayuntamiento para que nos envíe las llaves del domicilio. Cuando acudió allí no se las entregaron.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CORAL'and edp.apellido1='NEVADO'and apellido2='NAVARRO'),'2011-09-23','SE LE VAN A DAR 150 € PARA LAS SALIDAS QUE HACE A SU CASA QUE SERÁN DE UNA SEMANA COMO MÁXIMO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GREGORIO'and edp.apellido1='LOPEZ'and apellido2='CABRERA'),'2011-09-21','Se llama a Telefónica para restringir llamadas cuando supere los 30 € pero comentan que eso no se puede hacer.Lo que hemos hecho es que cuando se aproxime a esa cifra reciba un mensaje advirtiéndole que va a superar esa cifra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='BLAZQUEZ'and apellido2='ACEDO'),'2011-09-23','C.R. Hernando de Soto (924-025750). Conversación telefónica con Nieves, su Directora. La situación personal de D. Antonio ha mejorado desde que se ha hecho amigo de un nuevo residente: físicamente se encuentra mejor (el deterioro físico anterior era notable) y el consumo de alcohol, si bien persiste, es menor. Además, últimamente no pone ninguna pega para tomar su medicación y se muestra muy cordial y colaborador tanto con el personal como con los compañeros. En relación a este otro residente, desde el punto de vista afectivo le ha venido muy bien a D. Antonio, aunque también es cierto que dada la naturaleza excesivamente bondadosa de éste aquel se pueda estar aprovechando hasta cierto punto de él. Nieves volverá a tratar de convencerle de iniciar tratamiento rehabilitador de formaq voluntaria y programaremos, bien una visita a D. Antonio en el Centro o una visita de él a la Comisión Tutelar. Queda pendiente hablar con el E.S.M. de Jerez del que esperamos la llamada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='SOSA'and apellido2='MARTINEZ'),'2011-09-23','Pisos Tutelados de Helechal. Esperanza. Conversación telefónica (924-607118). Tras el Alta de D. José en el Hospital I. Cristina, las condiciones en las que llegó a la Residencia eran "lamantables": no podía caminar, llevaba pañales, no podía hablar con claridad, había que alimentarlo con batidos energéticos porque no quería comer...además, llegó sin ningún Informe médico, que posteriormente le enviaron por fax a petición de la Dirección de la Residencia. Le pido a Esperanza que me envíe por fax ese informe, junto con otro informe por parte de la dirección de los Pisos Tutelados concretando todo lo posible esas circunstancias y, a ser posible, otro informe del Médico/Enfermero de Familia de cuál era el estado de D. José en la primera cura que le hicieron tras salir del hospital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARCELO'and edp.apellido1='MANZANO'and apellido2='PEREZ'),'2011-09-23','Se recibe el Contrato de Admisión de la Residencia Villa de Hoyos en Hoyos (Cáceres.(927-514570).','2');
