insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='RANGEL'and apellido2='MONROY'),'2011-09-23','Entre en la Comisión escrito de la Dra. Agustina González Gargamala en relación a D. Francisco Rangel Monroy, informando sobre conductas disruptivas (sustracción de medicación) y solicitando como medida terapéutica y rehabilitadora para él y protectora para los demás, su traslado a otro Centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2011-09-26','Lugar que ocupa en la lista de espera para CRR: el 27º. Solicitud de preferencia: CRR Plasencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2011-09-23','Conversación telefónica con CS de Guadalupe.Se solicita por escrito Informe Médico a su Médica de Familia, Dra. Consolación Sánchez Valiente, en el que se haga constar la medicación que toma y cuál es 100% controlable (administración en C. Salud) y cuál no (en domicilio).Al CS acude puntualmente cada 15 días para inyectarse la medicación, y las pastillas que debe tomar en casa se las lleva y dice que sí sed las toma, pero sobre esto no se puede asegurar que sea así. Tiene cita programada en ESM de Trujillo el 4 de octubre con el Dr. Miguel Medina. Llamaremos tras esa consulta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2011-09-26','Teresa, Directora de Asoc.Vera.(Conv. Telef.).María josé se siente un poco desplazada desde que su amigo Pedro se fue al CRR de Plasencia: con él salía de paseo, la invitaba a tomar alguna cosa, etc. Desde que se fue, no quiere hacer nada, "se mete" con otros residentes, no está contenta con nada, pide más dinero para sus gastos. En los bares de la zona parece ser que a veces le fían, porque sí es cierto que es muy buena pagadora. Teresa cree que el desencadenante de este comportamiento, que había mejorado con anterioridad a la marcha de Pedro, ha sido precisamente esta marcha. El ingreso y posterior alta en el Hospital Virgen del Puerto, el pasado 23 de agosto, se produjo por haber tomado acetona, según Mª José, "...por que sabía que a Pedro lo iban a operar". Teresa cree que, si tomó algo, debió ser muy poco, porque ni siquiera le hicieron un lavado de estómago. Le ha propuesto llamar a Pedro para hablar con él, pero Mª José no quiere. Teresa me facilitará los teléfonos de los establecimientos que suele frecuentar Mª José para que no le fíen dinero, y de esta forma tratar de que trabaje para conseguirlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATILDE'and edp.apellido1='SORIA'and apellido2='ORTIZ'),'2011-09-27','YA LE ESTÁN INGRESANDO LAS DOS PENSIONES DE FRANCIA JUNTO CON LOS ATRASOS, SE COMUNICA A LA DIRECTORA DE LA RESIDENCIA SAN FRANCISCO PARA QUE CARGUEN EN LA CUENTA TODOS LOS MESES QUE SE DEBÍAN.','2');
