insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN'and edp.apellido1='GUTIERREZ'and apellido2='RONCERO'),'2011-09-29','Nos comunica María, Directora del CRR de Badajoz, que la próxima semana está citado D. Julián en el CRR de Plasencia para valorar su traslado y, posiblemente, de confirmarse, el mismo se produzca la semana siguiente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALMUDENA'and edp.apellido1='CORREYERO'and apellido2='PAREJO'),'2011-09-30','Ha acudido a Caja de Extremadura de Mérida con un chico que creemos será su novio a sacar el dinero semanal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARSENIA'and edp.apellido1='FERNANDEZ'and apellido2='SAN MIGUEL'),'2011-09-30','Antesdeayer, 28 de septiembre, recibimos información de SAR Quabitae acerca de que Dª Arsenia no acudía al Centro de Día desde primeros de septiembre. Lo habían hablado con la hija, Dª Pilar, y esta les había dicho que su madre se encontraba mal y que se iba a quedar en casa unos días. Puestos en contacto con Dª Pilar, esta nos comenta que había llevado a su madre al Médico de Familia el Dr. Carlos López, y que éste le había dicho que se quedara en casa unos días. La conversación fue muy breve. Llámamos al Centro de Salud de Valdepasillas para hablar con el Médico pero su jornada ayer empezaba a las cuatro de la tarde. Ayer, día 29, hablamos con el Médico y nos dijo que él no había tenido ninguna consulta con Dª Arsenia, pero quew preguntaría por si durante sus vacaciones algun compañero sustituto la hubiera atendido. Traté también de hablar con Dª Ángela Galán, cuya suegra es hermana? de Dª Arsenia pero no pude contactar con ella. Hoy, al habla con Dª Ángela, me comenta que desde principios de año creen haber apreciado un cierto deterioro en el estado de Dª Pilar, la hija. Últimamente la rutina familiar se ha interrumpido en varios aspectos desde finales de agosto: **Dª Pilar ha dejado de acudir con su madre los sábados por la tarde; **Sólamente han ido al campo un fin de semana, cuando antes iban las dos todas las semanas. **Refiere que desde principios de año cree que Dª Pilar no lleva a su madre al Médico. La tercera semana que faltó al C. de Día Dª Ángela fue la última vez que habló con ella: "...tienes que llevar a tu madre al Centro de Día, porque además, si no lo haces, la Junta te puede pedir responsabilidades..." Al parecer, la hija les dijo que no llevaba a su madre al Centro porque no podía caminar, pero según Dª Ángela eso no había pasado anteriormente. Pido a Dª Ángela que, si es posible, y con la excusa de haber hablado yo ayer con Dª Pilar, se pase por su casa para ver cómo están las cosas. Tras hablar con Dª Ángela, llamo al Dr. Carlos López, quien me confirma que, salvo con un compañero con el que no ha podido hablar y que atendió a pacientes suyos la semana pasada, ninguno ha atendido en estas últimas semanas a Dª Arsenia. Le comento la conversación mantenida con Dª Ángela y mi preocupación por la situación en la que se puedan encontrar madre e hija. Le pido que, en la medida de lo posible, realicen hoy una visita domiciliaria para comprobar la situación. Carlos toma nota de la dirección y le pido que me llamen con aquello que puedan averiguar. El Médico, tras la visita con la Enfermera, me comunica que ambas están bien. El motivo por el que Dª Pilar no ha llevado estas semanas a su madre al C. de Día ha siido porque Dª Arsenia , al parecer, se movía con más dificultad últimamente y su hija no la podía meter en el ascensor con la silla de ruedas. El médico le hizo ver la necesidad de que si esas dificultades para moverse se daban, con más motivo la tenía que llevar al C. de Día. En contacto con SAR Quavitae, hablo con Carmen, la T. Social. Quedamos en que este lunes acudirá la Fisioterapéuta, Sara, para recogerla, y valorarán esta dificultad para que se la pueda recoger todos los días como se venía haciendo anteriormente (antes bajaba las escaleras hasta la calle) o bien hay que facilitarle otra silla de ruedas para ello. hablo también con Dª Ángela para tranquilizarla sobre la situación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2011-09-30','Conversación con Miguel Medina. D. Juan tiene consulta en el ESM con Miguel el día 4 de octubre. Nos enviará por fax informe de la consulta, especificando tratamiento y adherencia al mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LAZARO'and edp.apellido1='LUBIAN'and apellido2='SANTANO'),'2011-09-30','Conversación telefónica con Eva, T.S. de Fomento. Requisitos para adjudicación de viviendas VPP. Se tramita a través del Ayto. en el que está empadronado y depende del nº de viviendas disponibles. Requisitos: ***Acreditar ingresos inferiores a 15.000 euros. ***Certificado de Empadronamiento. ***DNI. ***Libro de Familia. ***Informe Social explicando la situación de emergencia. ********************************************************************************************************************** Conversación telefónica con Miguel Medina. No ha tenido respuesta a su derivación a UME. Le pongo al corriente de la negativa a la misma. La alternativa, prescindiendo de ese paso intermedio por UME que ambos consideramos sería más conveniente, es la derivación a CRR por emergencia social. Quedamos en que entre el lunes y el martes tramitará dicha derivación y la Comisión, una vez asegurada la plaza, nos encargaremos de visitar personalmente a D. Lázaro en la Residencia para que entienda que este es el último recurso posible y que debe aprovecharlo en todos los sentidos. Comunico esta opción a Altagracia, la cual está de acuerdo, tratando de que sea lo más pronto posible. También se lo comunicamos a Nati, del Servicio de Gestión de Penas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARSENIA'and edp.apellido1='FERNANDEZ'and apellido2='SAN MIGUEL'),'2011-10-03','- Nos comunican desde Maprhe que Arsenia ha regresado a la residencia. Solicitan que vaya más aseada, al menos que le cambien la ropa con más frecuencia. Llamaremos a Angela para que lo organice.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='ANTUNEZ'and apellido2='SANZ'),'2011-10-04','Llamada telefónica de Inés, T. Soc. del Ayto. de Santa Amalia. Dª Josefa mantiene desde su ingreso en la Residencia una actitud agresiva con sus compañeros, llegando incluso a la agresión física también con algunas profesionales, incluso con amenazas con arma blanca. Inés nos enviará informe y propuesta. Se aconseja llamar al médico en las situaciones de crisis si se considera necesario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARSENIA'and edp.apellido1='FERNANDEZ'and apellido2='SAN MIGUEL'),'2011-10-04','Fallecida ayer tarde después de volver del C. de Día. Nos avisa Carmen, del C. de Día y lo confirmamos con Dª Ángela por teléfono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2011-10-05','Visita domiciliaria a D. Pedro y entrevista con su sobrina Cristina y el marido de ésta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2011-10-06','Se recibe en la Comisión Informe de su Médica Familia, la Dra. Consolación Sánchez, del C.Salud de Guadalupe (927-367217) con el tratamiento prescrito y su forma de administración. Pendiente de recibir el Informe del ESM de Trujillo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2011-10-05','Visita domiciliaria al piso que Dª Carmen, sin nuestro conocimiento, tenía alquilado a Dª Ricarda ¿? en la calle Corte de Peleas nº 75, 2ºA de Badajoz. Nos acompañó Carmen Lozano, Trabajadora Social del ESM Ciudad Jardín, a quien Dª Carmen le comentó esta situación, poniéndola a su vez en conocimiento de la Comisión. Problema con este alquiler: Dª Carmen no ha recibido el pago pactado de 350 euros/mes ninguno de los 18 meses que hace se firmó el contrato de alquiler, al parecer en una gestoría que actualmente ya no existe. Dª Carmen nos informó de que la inquilina le dijo que, ha cambio del alquiler, le haría los arreglos que fuesen necesarios en la vivienda. Puestos al habla con Dª Ricarda, ya que no estaba en el mencionado domicilio en el momento de la visita, gracias al teléfono que Dª Carmen Leal nos proporcionó, la información ofrecida por ésta, indignada y a la vez ofendida aparentemente ante la "acusación" de no pagar el alquiler fue la siguiente. Efectivamente ella había quedado con Dª Carmen en que, como no podía pagar dicho alquiler ya que había tenido que errar el bar y la tienda que tenía, ella a cambio le hacía todos los arreglos que necesitase la casa:-"He arregladola cocina ,que no se puede usted imaginar cómo estaba, he puesto un calentador eléctrico, ahora estoy comprando la lavadora..."-. Al parecer, Dª ricarda firmó un "documento" con Dª Carmen en la que esta se comprometía a recibir el pago del alquiler de la manera mencionada. Quedamos en que llamaríamos nuevamente a la inquilina para tener una entrevista con ella, en la que nos daría toda esa documentación a la que se refiere (facturas, documento de alquiler de la gestoría, el documento sobre el acuerdo al que al parecer habían llegado y todo lo que pueda confirmar lo dicho. Además, asegura desconocer que Dª Carmen estubiera tutelada. Dª Carmen nos hará llegar el contrato de alquiler a través de Carmen Lozano.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='ANTUNEZ'and apellido2='SANZ'),'2011-10-06','Se recibe en la Comisión Informe del SSB de Santa Amalia.','2');
