insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='CALVO'and apellido2='GONZALEZ'),'2011-10-07','Nos informa Chelo, T.Social de Valverde de Burguillos, que desde el Consultorio (924-570559)la Dra . Marisol Iglesias ha activado el 112 para trasladar a D. Luis a la UHB de Llerena. Previamente se había avisado a la Dra. Constanza, Psiquiatra de dicha Unidad (924 877 026), del posible ingreso de nuestro tutelado en el día de hoy. La Dra. confirma que esta persona no puede estar con su padre dado que este no le pueder atender, y que una vez estabilizado en UHB procederán a derivarlo a UME. 14:00h Chelo confirma el traslado a Llerena.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LAZARO'and edp.apellido1='LUBIAN'and apellido2='SANTANO'),'2011-10-07','Reunión con Yolanda, Jefa de Unidad de gestión de Recursos y con Manuela, Jefa de Sección de Discapacidad. No pse puede resolver este caso en tanto no se cree la nueva Comisión de Valoración de casos de Salud Mental. Se intentará el traslado de D. Lázaro a la Casa de la Misericordia del Padre Leocadio, manteniendo si es posible la prestación vinculada de la que dispone ahora, teniendo en cuenta que esta situación es provisional y que una vez funcione la Comisión de Valoración se estudiará la derivación a dispositivo de la Red de Salud Mental. Se comunica a Altagracia las gestiones que se están haciendo y quedo en visitar el próximo día 13 de octubre a D. Lázaro para hablar del traslado (él dice que se va a ir a su casa). Altagracia nos enviará la cuenta de la deuda contraída con la Residencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LAZARO'and edp.apellido1='LUBIAN'and apellido2='SANTANO'),'2011-10-07','-el lunes pte. de la respuesta de la Casa de Misericordia del Padre Leocadio sobre el acceso a plaza en Alcuescar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2011-10-11','-Visito la vivienda de Carmen en C/ Corte de Peleas , 75 que tiene alquilada a Dª Ricarda. El edificio es nuevo y la vivienda si bien necesita algunos arreglos está sumamente habitable. Tiene 4 habitaciones , un salón , una cocina y dos cuartos de baño , todo perfectamente amueblado. Algunos muebles son antiguos pero otros son totalmente nuevos ( mesa del salón y sillas , mesa y bancos de la cocina, dormitorios juveniles ... ) . La inquilina ha comprado la lavadora y el calentador nuevos. Quedamos pendiente que Ricarda enviarán un presupuesto de los gastos que le ha generado el piso y el documento que firmaron en el que no se le obligaba al pago del alquiler. - Carmen llevará la copia del contrato de alquiler a Carmen Lozano del ESM .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='BUENO'and apellido2='GUISADO'),'2011-10-11','- Acudo a notaria de Carlos Mateos en Badajoz acompañando a Juana. Se procede a la venta de la casa familiar que tenian en Alburquerque . Estaban presentes sus dos hermanos y la parte compradora. Se entregan en el acto 5400€ pte. de la compra , que se reparten entre los tres. Los 1800€ que le corresponden a Juana los ingresará en su cuenta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='CALVO'and apellido2='GONZALEZ'),'2011-10-11','Se pone en contacto con nosotros Carmen, de la Soc. Coop. "Ntro. Señor del Gran Poder" para dar de baja el SAD al haber ingresado a D. Luis. Se le pide que hagan un último servicio para desechar alimentos perecederos, desconexión de aparatos, etc. y dejar la vivienda en las mejores condiciones. Hablamos con Chelo, T. soc. de Valverde de Burguillos. Se pondrá en contacto con Carmen para pedir la llave á Dª Isabel, tía de D. Luis, y acudir un día, de esta semana a a ser posible, para hacer esa última limpieza. Chelo insiste en la necesidad de buscar un recurso conjunto donde puedan atender a padre e hijo. Hablamos de un Centro que Mensajeros de La Paz tiene en el norte de Cáceres. Recabaremos información sobre ello.Llamo a UHB de Llerena. El caso lo llevan la Dra. Constanza y el Dr.Francisco Zamora: quedo pendiente de su llamada.','2');
