insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GREGORIO'and edp.apellido1='LOPEZ'and apellido2='CABRERA'),'2011-10-11','Llega el Extracto de Caja de Badajoz, de esta cuenta no se ha sacado ningún reintegro en todo el año hay que ver el extracto la caixa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='BLAZQUEZ'and apellido2='ACEDO'),'2011-10-11','Visita recibida en la Comisión de D. Antonio acompañado por Nieves, la Directora de la Residencia de Mayores "Hernando de Soto". Explicamos a D. Antonio cuál es el papel de la Comisión en relación a su bienestar, y la necesidad de controlar, en el sentido de no consumir alcohol, su ingesta, tanto por motivos de salud como por el desarrollo de una buena convivencia en la Residencia convivencia. Hablamos también de su relación con otro residente, D. Alfonso, con el que desde que llegó hace una año ha establecido una muy buena relación desde el punto de vista afectivo, según nos manifieta Nieves. Más preocupante es esta relación en cuanto al dinero de D. Antonio. En la Residencia se sospecha que pueda estar aprovechándose de D. Antonio en este sentido: este pasado verano, D. Antonio sacó 1200euros para irse dos días con él de vacaciones. Confiesa que durmieron en el coche del amigo y que cenaban bocadillos...pero no dice en qué se gastaron el dinero. Reconoce que el paga casi siempre y casi todo, porque D. Alfonso no tiene dinero. Tratamos de hacerle entender que si continúa gastándose el dinero de esta forma llegará a no tener nada ahorrado. D. Antonio "se compromete" a no beber alcohol y a no gastar tanto dinero en su amigo. Nieves nos comenta que el venir a Mérida ha supuesto en la Residencia una "revolución", porque a D.Alfonso sae le ha metido en la cabeza que su amigo no iba a volver. desde ayer está en huelga de hambre y hoy ha puesto una reclamación en la Residencia denunciando el abuso al que se está sometiendo a D. Antonio. Quedamos con Nieves en que, dado que la Curatela no contempla el gasto de dinero para gastos "de bolsillo", no se puede limitar su cuenta. Estarán pendientes, si puede ser de forma semanal, de los movimientos ded la cuenta y caso de detectar alguno que exceda lo habitual nos lo comunicarán, poníendolo nosotros en conocimiento del Juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2011-10-11','Se recibe en la Comisión Informe Clínico del Dr. Miguel Medina, informándonos de la realización correcta del tratamiento psicofarmacólogico.','2');
