insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AQUILINO'and edp.apellido1='CAMACHO'and apellido2='ROMERO'),'2010-10-14','-incrementada su P. Orfandad simple a Absoluta = 639€ más 910€ de retrasos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='ANTUNEZ'and apellido2='SANZ'),'2011-10-14','Visita realizada al C. de Mayores "San Miguel", de Santa Amalia. Profesional de contacto Sefi, Enfermera. Cómo quedó reflejado en la incidencia anterior, Dª Josefa desde su ingreso mostró un comportamiento que suponía una alteración de la convivencia habitual de la Residencia. Sefi me comenta que antes dicho comportamiento se dirigía a residentes que tenían capacidad de respuesta ante él, pero que últimamente Dª Josefa pasa mucho más tiempo con residentes que se encuentran en una situación de inferioridad para "defenderse" respecto de ella. Según Sefi, Dª Josefa es consciente de lo que hace...o así lo parece, dado que cuando "se mete" con alguien sigue con esa persona durante un cierto tiempo. Hablé con Dª Josefa, quien negó estos hechos de agresiones, arañazos, amenazas con un cuchillo (de plástico y romo), etc. Daba la sensación de que realmente creía en que nada de esto había ocurrido, como si una vez sucedido perdiera la consciencia sobre ello. Como se ha dicho, sefi no opina así. La alternativa de cambio de Centro no se puede descartar, pero Sefi reconoce que si en la residencia se dispusiera de una persona que pudiera estar pendiente del comportamiento de Dª Josefa esta no provocaría ningún conflicto, porque no actúa de ese modo en presencia de los profesionales. Dicha disponibilidad no existe, pero tampoco existe en otros Centros. Coincido con Sefi en que recurrir, por ejemplo, a la unidad psiquiátrica de Felipe Trigo no es una opción en este caso, ya que Dª Josefa tiene muchas capacidades, tanto físicas como mentales, por lo que no sería conveniente para ella la estancia en dicha unidad. Va a iniciar un nuevo tratamiento (ver expte.) y se le informa de la posibilidad de traslado si persisite en este comportamiento. Sefi nos mantendrá informados de su evolución durante estas próximas semanas para ver si mi visita a podido influir en este sentido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='PIZARRO'and apellido2='GOMEZ'),'2011-10-13','Conversación telefónica con Cristina, T. Soc. Apba.12 (924-620329 y 924-620400). Refiere que Dª Consuelo se encuentra muy mal: se le ha detectado una masa hepática tumoral con metástasis a ovario dcho. No es operable en este momento hasta que se recupere de la embolia pulmonar sufrida este verano. Sigue bajando al C.O. pero se distrae mucho y se cansa . Cuando vuelve al piso se asusta mucho. Está animada para recibir visitas, pero su familia desconoce la gravedad de su situación. Tamara la va a ver los jueves o viernes. Está pendiente de realizarse un ecocardiograma transtorácico, un TAC de tórax-abdomnen con contraste y uina analítica.','2');
