insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LAZARO'and edp.apellido1='LUBIAN'and apellido2='SANTANO'),'2011-10-17','-Se nos deriva informe de la T.S. del ESM de Trujillo. -Gestiones a realizar : 1.Revisar la incapacidad pte por absoluta . Se envia solicitud firmada a este ESM. 2.Revisión CADEX. Se envia solicitud. 3.Revisión del PIA, pte. de su traslado a CRR , por el momento no se hará. Nos respetan la prestanción vinculada.','2');
