insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MATILLAS'and apellido2='JIMENEZ'),'2011-10-19','-sigue ingresada en el CRR de Plasencia donde fue derivada del CSS de Plasencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='CALVO'and apellido2='GONZALEZ'),'2011-10-19','Contacto telefónico recibido. Dra. Constanza. La evolución de D. Luis ha sido muy buena desde que ingresó en UHB. El próximo martes 25 de octubre ingresa en UME. Desconocemos cuánto tiempo de condena tiene que cumplir el padre. Se comunica esta situación a su Médica de Familia, Dra. Marisol. En su opinión, D. Luis no debe volver a vivir con su padre, sino que debería estar en un recurso residencial, por ejemplo, un piso tutelado: "Él, cuando no bebe, es una persona estupenda...pero en el momento que consume se deteriora rápidamente y enseguida se le nota. Pero con una buena adherencia al tratamiento podría llevar una vida normal". Propuesta para favorecer el contacto padre/hijo: derivación a CRR de D. Luis y Residencia de Mayores próxima para el padre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='LOPEZ'and apellido2='CABRERA'),'2011-10-19','SU TÍA NOS RECLAMA EL IMPORTE DEL IBI DE LA CASA QUE TIENEN A MEDIAS LOS HNOS. LOPEZ CABRERA CON ELLA, EL IBI HASTA EL AÑO 2007 YA SE PAGÓ CUANDO SE HICIERON LAS ESCRITURAS DE PARTICIÓN DE HERENCIA POR LO QUE PROCEDEMOS A PAGARLE LOS AÑOS 2008-2011.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GREGORIO'and edp.apellido1='LOPEZ'and apellido2='CABRERA'),'2011-10-19','SU TÍA NOS RECLAMA EL IMPORTE DEL IBI DE LA CASA QUE TIENEN A MEDIAS LOS HNOS. LOPEZ CABRERA CON ELLA, EL IBI HASTA EL AÑO 2007 YA SE PAGÓ CUANDO SE HICIERON LAS ESCRITURAS DE PARTICIÓN DE HERENCIA POR LO QUE PROCEDEMOS A PAGARLE LOS AÑOS 2008-2011.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2011-10-20','Hablamos con Elena, T.Soc. de "Las Cumbres". Nos propone la realización de un Curso de Peluquería para Margarita (ver información en expediente). Se le informa de la posibilidad de Traslado a Extremadura de Margarita para que, dado su alto nivel de integración y adaptación en "Las Cumbres", dicho traslado se pudiese realizar de la forma menos traumática posible, preparándola convenientemente para el mismo. Tras hablar con Elena, nos llama Eulogia, la Directora, para comemntarnos que NO se lo van a decir, porque ya cuando visitamos el Centro lo pasó basatante mal durante unos días pensando en que os la ibáis a llevar de allí, amenazando con suicidarse si esto ocurría. Eulogía considera mejor decírselo en el momento del traslado, como si fuera algo temporal. Este traslado lo tenemos que valorar para que el mismo sea lo más beneficioso para Margarita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='ANTUNEZ'and apellido2='SANZ'),'2011-10-21','Conversación telefónica con Teresa, Enfermera de la Residencia. Esta semana, tras nuestra visita del día 14 de octubre, Dª Josefa ha estado muy tranquila.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='RODRIGUEZ'and apellido2='CALERO'),'2011-10-21','Visita domiciliaria realizada con Carmen Díaz, T. Social del ESM de Badajoz. D. Juan tenía muy buen aspecto, aseado y bien vestido. Nos recibió en la puerta y fue muy educado durante toda la visita. Era consciente de las deudas que tenía y de la parte que ya había pagado en metálico, hecho este que desconocíamos en la Comisión. Acuerdos a los que llegamos: 1.-Acepta voluntariamente la administración de sus cuentas. 2.-Acepta sacar todas las semanas 150 euros para alimentación y otros gastos. 3.-Acepta el pago de la deuda con Collecta, de la cual dice haber pagado ya 4 recibos (encontró tres de ellos pero dice estar seguro de haber pagado otro más). 4.-Desea darse de alta en Digital+, pagando previamente la deuda de 274,98 euros. 5.-Solicita ingreso voluntario en Residencia, de Badajoz (capital) en primera opción y en Cáceres (capital) en segunda. Desea mantener el contacto y la proximidad con los profesionales que le están atendiendo en Badajoz: se siente más seguro.','2');
