insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2011-10-24','-Acude a la oficina el inquilino de la cochera ( Juan Silva tf 687572742), ha entregado la copia de las llaves de la cochera , pues las cambió. Comenta que en enero se le termina el contrato y que quiere renovarlo . -Nos llama Carmen Leal ( 689024423) comentando el mismo tema , no quiere renovarle el alquiler pq quiere alquilarlo para coches que sacará más dinero . Quedo pte . con ella visitarla a primeros de diciembre para ver el tema . Me comenta que la inquilina del piso tb ha ido a visitarla para discutir con ella , y que estaria dispuesta a pagar 200€ por el piso sin abonar lo que le debe. Le pido que le acerque a Carmen ( ESM ) los contratos que tiene para solucionar el tema.','2');
