insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL GONZALO'and edp.apellido1='MORENO'and apellido2='GOMEZ'),'2011-10-25','Información Aprosuba 9. La semana pasada hablé con Ana, C. Ocupacional. Ángel no está cumoliendo la medida judicial de 20 días de trabajo a la Comunidad. Se le indicó que hiciese el correspondiente Informe a Servicios Sociales Penitenciarios reflejando exactamente la realidad de lo que estaba sucediendo. Hoy me llama Maribel, Directora Residencia, comentando la misma sistuación y, además, que Ángel no ha querido ir a "La Encomienda". Hablo con Ángel y me dice que no quiere ir, que quiere que le demos su pensión y que tiene una deuda con un chico que le vendió un móvil por 300 euros, el cual, a su vez, lo vendió por 20 euros a otro (nada creíble). Llamo a Susana, de S.S. Penitenciarios. Alberto, el Jefe de Servicio, no está hoy. Quedo en hablar mañana con él. Le pido que envíen una carta a Ángel advirtiéndole de lo que para él supondría el quebrantamiento de la pena, como un último intento para que la cumpla. Caso de no hacerlo, se daría cuenta al Juez de la situación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='GILARTE'and apellido2='PEREZ'),'2011-10-25','NO TIENE SEGURO DE DEFUNCION','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LAZARO'and edp.apellido1='LUBIAN'and apellido2='SANTANO'),'2011-10-25','-Queda pte. enviar a la Unidad de Dependencia el contrato de Lazaro con la Casa de la Misericordia de Pinofranqueado . Hemos acordado que se les dará la totalidad de su pensión en concepto de plaza cubriendo todos sus gastos personales. Las pagas extras se las entregaremos al " el Conquitador " en concepto de deuda .( se deben 2494,06€)','2');
