insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LAZARO'and edp.apellido1='LUBIAN'and apellido2='SANTANO'),'2011-10-25','Se envía fax al Servicio de Gestión de Penas (Cáceres) informando de la nueva residencia de D. Lázaro, dirección y teléfono para comumicarlo a su vez al Juzgado. Llamo a la Casa de la Misericordia. Hablo con Elisabeth, Cuidadora. El Padre Fernando no está en estos momentos, pero le dirá que he llamado y estamos a la espera del Contrato de Admisión. Respecto a D. Lázaro, nos dice que se encuentra bien, pero que constantemente está diciendo que se quiere ir (como en "El Conquistador". No obstante, parece que se le convence y tranquiliza fácilmente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2011-10-25','Conversación con Dra. Araceli Sánchez, Psiquiatra de Dª Margarita (920-358001. Ext. 57569). Miguel (Enfermero). Araceli considera que, dado el nivel de integración y adapatación en el Centro, el traslado va a suponer un problema importante para Dª Margarita: "Ella se siente feliz aquí". Nos enviará Informe valorando las consecuencias de dicho traslado, así como la forma más adecuada de realizarlo. Además, enviaremos también dicho Informe al CADEx para que valoren su perfil y nueva valoración del grado de minusvalía, para poder solicitar en su caso PNC. Desde "Las Cumbres" nos enviarán Informe Social y Psicológico para que el CADEx pueda realizar esta valoración sin necesidad de traslado de expediente.','2');
