insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='CUENCA'and apellido2='SILVA'),'2011-10-26','Conversación con D. David Cuenca Silva, hermano de D. José. Se le pide fotocopia compulsada de las escrituras del piso en las que aparezta nuestro tutelado como usufructuario del mismo. Una vez la tengamos, daremos de alta nuevamente la luz. Las enviará. Respecto a la ocupación de esta vivienda por parte de su hijo, D. David Cuenca Miranda, una vez tengamos esa documentación redactaremos un contrato de alquiler en términos que ya se discutirán en su momento. Si llegamos al alquiler, debemos hacer antes una visita al domicilio para ver las condiciones en que se encuentra.','2');
