insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA NIEVES'and edp.apellido1='HERREROS'and apellido2='ORIVE'),'2011-10-26','Conversación telefónica con Paqui, hija de Dª Mª Nieves.(619-136632). Ingreso de su madre en Hospital. Situación de la relación con su padre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2011-10-26','Entrevista con Ildefonso (Ati). Acude a la Comisión para "sincerarse". En esta ocasión pide permiso para cerrar la puerta del despacho. Le preocupa que el Juzgado vuelva a pedir aclaración de sus cuentas como en la última Rendición Anual. A raiz de la ruptura con Joaquina, el 11 de junio, Ati comenta que se sintió muy mal: ""Joaquina y su madre me estaban acosando. Joaquina exigía uns gastos en ropa, limpieza, etc. que tenía que cubrir yo, además de limpiar, hacer la comida, etc. Si a alguna cosa le decía que no ella entraba en crisis. Yo no tenía valor para decirle que lo quería dejar. Fuis al médico de cabecera para que me recetara algún estimulante, para coger valor para decírselo...pero no me lo recetó. Cuando el otro día me preguntaste si estaba consumiendo algo te dije que no, pero me quedé con mal cuerpo, me sentía culpable por haberte mentido y por eso te pedí hablar hoy contigo a solas. Para hablar con Joaquina necesitaba valor, y "me puse bien" de cocaína (fumada). Mi consumo desde entonces a sido poco (le pregunté si todos los día y dijo que no, que de vez en cuando) y no tomo nada desde el 20 de septiembre. Me gustaría que si os piden justificación de los gastos desde el Juzgado, les hicieses comprender estas circunstancias, que me han hecho gastar más de la cuenta en ropa, cenas, viajes (Utrera), cine, tabaco...y la coca. pero desde finales de septiembre tengo todos los justificantes y facturas de lo que he ido comprando. El pasado verano me ocurrió lo mismo: se vinieron a vivir con nosotros el hijo de Joaquina y mi hermano. Al final les tuve que decir que se fueran porque el gasto que tenía que soportar era inaguantable. Esto fue otro motivo de crisis para ella."" Una vez de alta en el CSS de Mérida, está acudiendo al ESM de Mérida, con el Dr.Félix. Solo ha tenido una consulta hasta ahora.La próxima será el 5 de enero. Al Psiquiatra no le ha contado nada ni de su situación sentimental, relación que considera rota definitivamente como pareja, si bien no como amistad (siguen hablando por teléfono ahora que ella está con sus padres en Barcelona, ni tampoco sobre su consumo. Sobre el tema del consumo insisto en los riesgos que supone no sólo para su salud y su economía, sino también los derivados de las relaciones que pueda mantener para conseguir la droga. Le propongo pedir un adelanto de su cita en Salud Mental, pero dice que no, que prefiere hablar él con su médico de este tema. Se le propone también la alternativa de que si el ve que su actitud le va llevando inevitablemente al consumo, que nos lo diga y podemos hablar con su Psiquiatra del CSS para ver cómo ayudarle. Según él, el problema ya no existe...pero reconoce que pasa por momentos de "bajón" y que necesitaría que su médico le recetase "algo" para esos momentos. Pendiente de hablar con su Psiquiatra del ESM de Mérida.','2');
