insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA NIEVES'and edp.apellido1='HERREROS'and apellido2='ORIVE'),'2011-10-26','Conversación con el Dr.Romerales. Dª Mª Nieves está ingresada en la 3ª planta,habitación 165, Medicina Interna, del Hospital Don Benito-Villanueva. Ingresó por un cuadro febril. Desde ingreso no ha vuelto a tener fiebre. Se le están realizando una serie de pruebas dependiendo de cuyos resultados se le dará el alta en una fecha u otra. Enviarán Informe de Alta a la Residencia "Felipe Trigo" cuando se produzca. Pedirlo allí. Se comunica esta información a su hija Paqui, presocupada porque pensaba que el motivo del ingreso había sido algo relacionado con el corazón. Van a venir este fin de semana a ver a su madre. Respecto a la existencia de un seguro de deceso, sabe que cuando era pequeña se pagaba una poliza a Santa Lucía, pero desconoce si se mantiene la misma o no. Se comunica también todo esto a Verónica (T. Social).','2');
