insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='LUBIAN'),'2011-10-27','Conversación con el Padre Frenando. D. Lázaro se encuentra bien, se relaciona con los demás residentes y en algún caso colabora en tranquilar a alguno que se muestra nervioso. Tenía un problema importante de callos, en tratamiento por la podóloga y también con las uñas. Mantiene la idea recurrente de quererse marchar y tiene siempre hecha la bolsa, pero se le olvida enseguida. Respecto al contrato de admisión, los términos en que está redactado quedan aclarados por el Padre Frenando en los mismos términos de la conversación que mantuve con él hace unos días: los 1000 euros incluyen todos los gastos (ropa, tabaco, dinero de bolsillo, etc.) porque nuestro tutelado no tiene más capacidad que la que le dan esos ingresos, recordando además la deuda pendiente con la Residencia "El Conquistador". El Padre Fernando propone hacer un anexo al contarto haciéndolo constar así, pero no lo cree necesario. En la ficha de D. Lázaro lo hará constar así para conocimiento del resto del personal del Centro.','2');
